<template><ModulePageShell title="PDCA持续改进" description="服务端保存改进周期与指标快照"><template #toolbar><a-space><a-button :loading="loading" @click="reload">刷新</a-button><a-button type="primary" @click="openCreate">登记周期</a-button></a-space></template><a-alert v-if="error" type="error" show-icon>{{error}}</a-alert><a-empty v-else-if="!loading&&!cycles.length" description="暂无PDCA周期"/><a-card v-else class="section-card" :bordered="false" title="改进周期"><a-table :data="cycles" row-key="cycleId" :pagination="false"><a-table-column title="周期ID" data-index="cycleId"/><a-table-column title="标题" data-index="title"/><a-table-column title="类型" data-index="cycleType"/><a-table-column title="开始" data-index="startDate"/><a-table-column title="结束" data-index="endDate"/><a-table-column title="状态" data-index="status"/></a-table></a-card><a-modal v-model:visible="visible" title="登记PDCA周期" :ok-loading="saving" @ok="save"><a-form :model="form" layout="vertical"><a-form-item label="标题" required><a-input v-model="form.title"/></a-form-item><a-form-item label="周期类型" required><a-select v-model="form.cycleType"><a-option value="monthly">月度</a-option><a-option value="quarterly">季度</a-option><a-option value="special">专项</a-option></a-select></a-form-item><a-form-item label="日期范围" required><a-range-picker v-model="form.range" value-format="YYYY-MM-DD"/></a-form-item></a-form></a-modal></ModulePageShell></template>
<script setup lang="ts">import dayjs from'dayjs';import{onMounted,reactive,ref}from'vue';import{Message}from'@arco-design/web-vue';import ModulePageShell from'@/components/shared/ModulePageShell.vue';import{pdcaApi,type PdcaCycleApi}from'@/api/clinicalExtensions';const cycles=ref<PdcaCycleApi[]>([]),loading=ref(false),saving=ref(false),error=ref(''),visible=ref(false);const form=reactive({title:'',cycleType:'monthly',range:[dayjs().startOf('month').format('YYYY-MM-DD'),dayjs().endOf('month').format('YYYY-MM-DD')]});async function reload(){loading.value=true;error.value='';try{cycles.value=(await pdcaApi.listCycles(1,100)).list;}catch(e){cycles.value=[];error.value=`加载失败：${(e as Error).message}`;}finally{loading.value=false;}}function openCreate(){form.title='';visible.value=true;}async function save(){if(!form.title.trim()){Message.warning('标题不能为空');return;}saving.value=true;try{await pdcaApi.createCycle({title:form.title.trim(),cycleType:form.cycleType,startDate:form.range[0],endDate:form.range[1]});visible.value=false;await reload();Message.success('PDCA周期已保存并回读');}catch(e){Message.error((e as Error).message);}finally{saving.value=false;}}onMounted(reload);</script>
